void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Espinosa_1", UpperFirst(GetAddress_Form(NPChar)));			link.l1 = StringFromKey("Espinosa_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("Espinosa_3", GetAddress_Form(NPChar));			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "2";		break;		case "2":			dialog.text = StringFromKey("Espinosa_4", GetAddress_Form(NPChar));			link.l1 = StringFromKey("Espinosa_5");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("Espinosa_6", UpperFirst(GetAddress_Form(NPChar)));			link.l1 = StringFromKey("Espinosa_7");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("Espinosa_8", GetAddress_Form(NPChar));			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "5";		break;		case "5":			AddMoneyToCharacter(pchar, 750000);			dialog.text = StringFromKey("Espinosa_9", UpperFirst(GetAddress_Form(NPChar)));			link.l1 = StringFromKey("Espinosa_10");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("Espinosa_11", UpperFirst(GetAddress_Form(NPChar)));			link.l1 = StringFromKey("Espinosa_12");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("Espinosa_13", UpperFirst(GetAddress_Form(NPChar)));			link.l1 = StringFromKey("Espinosa_14");			link.l1.go = "exit";			NextDiag.TempNode = "8";		break;		case "8":			dialog.text = StringFromKey("Espinosa_15", UpperFirst(GetAddress_Form(NPChar)));			link.l1 = StringFromKey("Espinosa_16");			link.l1.go = "9";		break;		case "9":			dialog.text = StringFromKey("Espinosa_17");			link.l1 = StringFromKey("Espinosa_18");			link.l1.go = "exit";			NextDiag.TempNode = "10";		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}